mapper.update:
UPDATE COMMUNITY
SET COMM_INQIRE_CNT = COMM_INQIRE_CNT + 1
WHERE COMM_NO = #{commNo}

mapper.select:
SELECT COUNT(*)
FROM COMMUNITY_LIKE
WHERE CLKE_COMM_NO = #{commNo}
  AND CLKE_MBR_ID = #{mbrId}

mapper.insert:
INSERT INTO COMMUNITY_LIKE (
    CLKE_COMM_NO,
    CLKE_MBR_ID
)
VALUES (
    #{commNo},
    #{mbrId}
)

mapper.delete:
DELETE FROM COMMUNITY_LIKE
WHERE CLKE_COMM_NO = #{commNo}
  AND CLKE_MBR_ID = #{mbrId}

mapper.update:
UPDATE COMMUNITY
SET COMM_LIKE_CNT = COMM_LIKE_CNT + 1
WHERE COMM_NO = #{commNo}

UPDATE COMMUNITY
SET COMM_LIKE_CNT = GREATEST(COMM_LIKE_CNT - 1, 0)
WHERE COMM_NO = #{commNo}

mapper.select:
SELECT HTAG_NO
FROM HASHTAG
WHERE HTAG_TAG_NAME = #{tagName}

